using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddMcpServer()
    .WithHttpTransport()
    .WithToolsFromAssembly()
    .WithPromptsFromAssembly()
    .WithResourcesFromAssembly();

var app = builder.Build();
app.MapMcp();                      // MCP endpoint at /mcp (Streamable HTTP)
app.MapGet("/health", () => "ok"); // health check for containers
app.Run();

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Configuration",
        MimeType = "application/json")]
    [Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Gets the value of a configuration setting by key.")]
    public static string GetSetting(
        [Description("The configuration key to look up (e.g., 'MaxRetries')")] string key)
    {
        var settings = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
        {
            ["Environment"] = "Production",
            ["MaxRetries"] = "3",
            ["TimeoutSeconds"] = "30"
        };

        return settings.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Unknown setting: {key}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListSettings()
    {
        return string.Join("\n", "Environment", "MaxRetries", "TimeoutSeconds");
    }
}

